const QUESTIONS_CCZT_C1 = [
  { id:60101, domain:1, level:1, question:"What phrase best captures the foundational mindset of Zero Trust architecture?", options:["Never trust, always verify every request regardless of where it originates from","Trust the internal network but verify all external connections at the firewall","Verify users once at login and then trust them for the entire active session","Trust devices that are physically located inside the corporate office building"], correct:0, explanation:"Zero Trust's core principle is 'never trust, always verify'; the others reintroduce implicit trust based on location or one-time checks." },
  { id:60102, domain:1, level:2, question:"In Zero Trust, what does the principle 'assume breach' primarily imply for design?", options:["Operators should assume the perimeter firewall will always stop external attackers","Operators should assume attackers are already present and limit potential blast radius","Operators should assume internal users are inherently trustworthy and low risk","Operators should assume encryption alone is enough to prevent any data loss"], correct:1, explanation:"Assume breach means designing as if adversaries are already inside, minimizing blast radius; it rejects reliance on the perimeter or implicit internal trust." },
  { id:60103, domain:1, level:2, question:"Which concept does Zero Trust explicitly seek to eliminate from network design?", options:["All forms of encryption applied to data while it moves across networks","The use of multi-factor authentication for privileged administrator accounts","Implicit trust granted to anything based merely on its network location","Centralized logging of authentication events for later security analysis"], correct:2, explanation:"Zero Trust removes implicit, location-based trust; encryption, MFA, and logging are tools it actively relies upon." },
  { id:60104, domain:1, level:3, question:"The term 'protect surface' in Zero Trust refers to which of the following?", options:["The total external attack surface exposed to the public internet at large","The collection of all firewalls and intrusion detection sensors deployed","The set of user endpoints that connect remotely through a corporate VPN","The critical data, applications, assets, and services that must be defended"], correct:3, explanation:"The protect surface is the DAAS (Data, Applications, Assets, Services) that matters most; it is far smaller than the broad attack surface." },
  { id:60105, domain:1, level:1, question:"What does the acronym DAAS stand for in the Zero Trust protect-surface model?", options:["Data, Applications, Assets, and Services that the organization must safeguard","Detection, Analysis, Alerting, and Surveillance of all network-based threats","Devices, Accounts, Access, and Sessions managed by the identity provider tool","Defense, Authentication, Authorization, and Segmentation network controls"], correct:0, explanation:"DAAS = Data, Applications, Assets, Services, the elements that make up the protect surface; the other expansions are invented." },
  { id:60106, domain:1, level:2, question:"Why is the protect surface preferred over the attack surface as a design focus?", options:["It includes every possible threat vector, making it more complete to defend","It is much smaller and knowable, so controls can be placed precisely around it","It changes constantly with the internet, forcing continuous broad monitoring","It is defined entirely by the perimeter firewall rules already in production"], correct:1, explanation:"The protect surface is small and well defined, allowing tight controls; the attack surface is vast and ever-expanding, making it impractical to defend everywhere." },
  { id:60107, domain:1, level:2, question:"A 'microperimeter' in Zero Trust is best described as which of the following?", options:["A single large boundary surrounding the entire corporate campus network","A demilitarized zone positioned between the internet and the intranet edge","A tight boundary placed as close as possible to a specific protect surface","A VPN tunnel that encrypts all traffic between two remote office locations"], correct:2, explanation:"Microperimeters wrap controls tightly around individual protect surfaces; the others describe traditional perimeter or DMZ constructs." },
  { id:60108, domain:1, level:3, question:"Which traffic direction does Zero Trust emphasize controlling that perimeter models often neglect?", options:["North-south traffic moving between the internet and the data center edge","Outbound traffic leaving the network toward external cloud service providers","Broadcast traffic confined to a single local area network VLAN segment","East-west traffic moving laterally between systems inside the environment"], correct:3, explanation:"Traditional perimeters focus on north-south traffic; Zero Trust adds scrutiny to east-west (lateral) traffic to limit movement after a breach." },
  { id:60109, domain:1, level:1, question:"How does Zero Trust most directly hinder an attacker's lateral movement?", options:["By segmenting access so a compromised asset cannot freely reach others","By encrypting all stored data so attackers cannot read files at rest","By blocking all inbound connections from the public internet at the edge","By requiring antivirus software on every endpoint joined to the domain"], correct:0, explanation:"Segmentation and per-resource authorization stop a compromised host from pivoting; encryption and edge blocking do not by themselves prevent internal pivoting." },
  { id:60110, domain:1, level:2, question:"In Zero Trust, identity is often described as which architectural element?", options:["A legacy concern that matters less than securing the network perimeter","The new control plane that policy decisions are increasingly built around","A static attribute set once at onboarding and rarely re-evaluated again","An optional layer applied only to highly privileged administrator accounts"], correct:1, explanation:"Zero Trust treats identity as the primary control plane for access decisions; it is dynamic and applies to all subjects, not just admins." },
  { id:60111, domain:1, level:2, question:"What is the role of continuous verification in a Zero Trust model?", options:["Trust is established at the firewall and remains fixed for the whole session","Trust is verified only when a user changes their password or device","Trust is constantly re-evaluated rather than granted once and left unchecked","Trust is delegated to the operating system after a successful domain login"], correct:2, explanation:"Continuous verification re-assesses trust throughout a session as context changes; one-time checks contradict the model." },
  { id:60112, domain:1, level:3, question:"Which statement best contrasts Zero Trust with a traditional perimeter model?", options:["Zero Trust trusts the internal LAN; the perimeter verifies every single request","Both models grant broad implicit trust once a device joins the local network","Both models rely solely on a single firewall to make all access decisions","Zero Trust verifies every access request; the perimeter trusts whatever is inside"], correct:3, explanation:"The perimeter model trusts insiders by default; Zero Trust verifies every request regardless of location." },
  { id:60113, domain:1, level:1, question:"How does Zero Trust generally relate to a remote-access VPN?", options:["ZT grants access per resource, whereas a VPN often opens broad network access","ZT and a VPN are identical because both encrypt traffic over the internet","ZT requires a VPN to function because all verification happens in the tunnel","ZT replaces encryption entirely, so a VPN's tunnel is no longer necessary"], correct:0, explanation:"A classic VPN drops a user onto the network with broad reach; Zero Trust grants narrow, per-resource access instead." },
  { id:60114, domain:1, level:2, question:"How does Zero Trust relate to the older concept of defense-in-depth?", options:["It fully replaces defense-in-depth, making layered controls unnecessary now","It complements defense-in-depth by adding identity-centric, granular controls","It contradicts defense-in-depth by removing all but a single control layer","It is identical to defense-in-depth and introduces no new ideas of its own"], correct:1, explanation:"Zero Trust builds on and complements layered defense-in-depth with identity-centric, fine-grained verification rather than replacing it." },
  { id:60115, domain:1, level:2, question:"Which pillar is NOT one of the CISA Zero Trust Maturity Model pillars?", options:["Identity as a pillar governing how subjects are authenticated and authorized","Devices as a pillar covering the security posture of connecting endpoints","Perimeter Firewalls as a distinct standalone foundational pillar of trust","Data as a pillar addressing classification and protection of information"], correct:2, explanation:"CISA's pillars are Identity, Devices, Networks, Applications & Workloads, and Data; 'perimeter firewalls' is not a pillar." },
  { id:60116, domain:1, level:3, question:"Which set correctly lists the five core CISA Zero Trust Maturity Model pillars?", options:["Identity, Firewalls, Routers, Switches, and Endpoint Antivirus tools","People, Process, Technology, Governance, and Budget allocation tracking","Confidentiality, Integrity, Availability, Authenticity, and Non-repudiation","Identity, Devices, Networks, Applications and Workloads, and Data"], correct:3, explanation:"The five CISA pillars are Identity, Devices, Networks, Applications & Workloads, and Data; the others mix unrelated concepts." },
  { id:60117, domain:1, level:1, question:"In the CISA model, which capabilities cut across all five pillars?", options:["Visibility and Analytics, Automation and Orchestration, and Governance","Encryption, Firewalls, and Intrusion Prevention deployed at the edge","Backup, Disaster Recovery, and Business Continuity planning processes","Procurement, Vendor Management, and Software Licensing oversight tasks"], correct:0, explanation:"CISA defines three cross-cutting capabilities: Visibility & Analytics, Automation & Orchestration, and Governance." },
  { id:60118, domain:1, level:2, question:"Which historical effort is widely credited as an early enterprise Zero Trust implementation?", options:["Microsoft's Active Directory domain model that trusted joined machines","Google's BeyondCorp initiative, which removed reliance on the internal network","Cisco's network admission control that scanned devices at the LAN edge","The original IPsec VPN standard that tunneled traffic between sites"], correct:1, explanation:"Google's BeyondCorp is a landmark early Zero Trust deployment; the others are traditional network or VPN technologies." },
  { id:60119, domain:1, level:2, question:"Which analyst framework helped popularize the Zero Trust eXtended (ZTX) concept?", options:["Gartner, through its Magic Quadrant for next-generation firewall vendors","NIST, through its Cybersecurity Framework function categories and tiers","Forrester Research, which expanded Zero Trust into a broader ecosystem model","ISO, through its 27001 information security management certification scheme"], correct:2, explanation:"Forrester introduced Zero Trust and later the ZTX ecosystem framework; the others are separate organizations and standards." },
  { id:60120, domain:1, level:3, question:"Who is generally credited with originally coining the term 'Zero Trust'?", options:["Bruce Schneier in his early writings on applied network cryptography","Whitfield Diffie as part of his work on public-key key exchange","Dan Kaminsky during his research into DNS protocol vulnerabilities","John Kindervag while at Forrester Research articulating the model"], correct:3, explanation:"John Kindervag coined 'Zero Trust' at Forrester; the other figures are known for unrelated cryptography or DNS work." },
  { id:60121, domain:1, level:1, question:"What is the 'trust algorithm' in a Zero Trust architecture responsible for?", options:["Evaluating inputs to decide whether to grant access to a given resource","Encrypting all data at rest using a rotating set of symmetric keys","Routing network packets along the lowest-latency path to a destination","Generating one-time passwords for users during their initial enrollment"], correct:0, explanation:"The trust algorithm is the decision process that weighs signals to grant or deny access; the others are unrelated networking or crypto functions." },
  { id:60122, domain:1, level:2, question:"Per-session access in Zero Trust means access decisions are made how?", options:["Granted once at network join and retained until the machine reboots","Granted on a per-request basis and re-evaluated as context changes","Granted permanently to a role and never revisited after provisioning","Granted by the firewall based solely on the source IP address range"], correct:1, explanation:"Zero Trust evaluates access per session/request and re-checks it; persistent grants based on join or IP contradict the model." },
  { id:60123, domain:1, level:2, question:"How many high-level tenets does NIST SP 800-207 enumerate for Zero Trust?", options:["Three tenets covering only identity, device, and network controls","Twelve tenets aligned one-to-one with common compliance frameworks","Seven tenets describing how a Zero Trust architecture should behave","Five tenets that map directly to the five CISA maturity pillars"], correct:2, explanation:"NIST SP 800-207 lists seven tenets; the other counts are incorrect." },
  { id:60124, domain:1, level:3, question:"Which is a common misconception about Zero Trust that practitioners should reject?", options:["That Zero Trust requires verifying identity and context for each request","That Zero Trust applies the principle of least privilege to all subjects","That Zero Trust assumes the environment may already be compromised","That Zero Trust is a single product an organization can simply buy and deploy"], correct:3, explanation:"Zero Trust is a strategy and architecture, not a single purchasable product; the other statements are accurate." },
  { id:60125, domain:1, level:1, question:"Least privilege as applied in Zero Trust means subjects receive what level of access?", options:["Only the minimum access required to perform the specific task at hand","Broad standing access to everything within their assigned business unit","Full administrative rights to simplify troubleshooting and support work","Access equal to the most privileged member of their reporting team"], correct:0, explanation:"Least privilege limits each subject to the minimum needed; broad or admin-equivalent grants violate the principle." },
  { id:60126, domain:1, level:2, question:"In Zero Trust terminology, what is a 'subject'?", options:["A network segment that has been carved out for sensitive workloads","An entity such as a user or service requesting access to a resource","A firewall rule that permits traffic between two defined zones","A data classification label applied to documents and database rows"], correct:1, explanation:"A subject is the requesting entity (user, service, device); the others describe segments, rules, or labels, not subjects." },
  { id:60127, domain:1, level:2, question:"In Zero Trust terminology, what is a 'resource'?", options:["The credential a user presents when authenticating to an identity provider","The policy decision point that evaluates whether to permit a request","An asset such as data, an application, or a service that a subject accesses","The encrypted tunnel established between a client and a gateway device"], correct:2, explanation:"A resource is the thing being accessed (data, app, service); the others are credentials, decision points, or transport." },
  { id:60128, domain:1, level:3, question:"What distinguishes a policy decision point from a policy enforcement point?", options:["The decision point blocks packets while the enforcement point only logs them","Both perform identical functions and the labels are interchangeable terms","The enforcement point sets policy while the decision point ignores context","The decision point evaluates policy while the enforcement point applies the verdict"], correct:3, explanation:"The PDP makes the access decision; the PEP enforces it by allowing or blocking the connection. They are distinct roles." },
  { id:60129, domain:1, level:1, question:"An 'implicit trust zone' is best understood as which of the following?", options:["An area where entities are trusted automatically without further checks","A segment where every packet is inspected and re-authorized continuously","A region of the network with the strongest encryption requirements applied","A quarantine zone where suspected compromised devices are isolated"], correct:0, explanation:"Implicit trust zones grant automatic trust to whatever is inside them, which Zero Trust seeks to shrink or eliminate." },
  { id:60130, domain:1, level:2, question:"Why does Zero Trust discourage trusting an entity based on its IP address?", options:["IP addresses are encrypted in transit and cannot be read by enforcement points","IP location can be spoofed or compromised and does not prove trustworthiness","IP addresses change too rapidly for any firewall to track them reliably","IP-based rules are illegal under most modern data protection regulations"], correct:1, explanation:"Network location and IP do not establish identity or integrity and can be spoofed; Zero Trust verifies identity and context instead." },
  { id:60131, domain:1, level:2, question:"Which statement about Zero Trust and the corporate LAN is accurate?", options:["Devices on the internal LAN are automatically trusted to reach all servers","The internal LAN is exempt from authentication to reduce user friction","Being on the internal LAN does not by itself entitle a device to any access","Only the internal LAN needs Zero Trust controls, never remote connections"], correct:2, explanation:"Zero Trust removes location-based trust; sitting on the LAN grants nothing without verification, and controls apply everywhere." },
  { id:60132, domain:1, level:3, question:"Device trust in Zero Trust contributes to access decisions in what way?", options:["Any device is trusted as long as the user provides a valid password once","Devices are trusted permanently after a one-time enrollment certificate scan","Device posture is irrelevant because identity alone determines all access","A device's security posture is assessed as a signal before access is granted"], correct:3, explanation:"Zero Trust evaluates device posture (patch level, compliance) as a signal; identity alone is insufficient and trust is not permanent." },
  { id:60133, domain:1, level:1, question:"What does 'dynamic' or 'policy-based' access mean in Zero Trust?", options:["Access is granted by policy using real-time signals and can change over time","Access is hard-coded into static firewall ACLs that rarely ever change","Access is decided by the user's manager through a manual ticket process","Access is fixed at provisioning and only altered during annual reviews"], correct:0, explanation:"Dynamic policy-based access uses real-time context to decide and adjust access; static ACLs and manual processes are the opposite." },
  { id:60134, domain:1, level:2, question:"Which benefit is most directly associated with adopting Zero Trust?", options:["Complete elimination of all phishing emails reaching user inboxes","Reduced blast radius and limited lateral movement after a compromise","Guaranteed prevention of every possible data breach without exception","Removal of the need for any logging or monitoring across the estate"], correct:1, explanation:"Zero Trust reduces blast radius and lateral movement; it does not guarantee zero breaches or remove the need for monitoring." },
  { id:60135, domain:1, level:2, question:"Which is a realistic limitation organizations face when adopting Zero Trust?", options:["It works only for cloud environments and cannot apply to on-premises systems","It removes the need for any identity provider once microperimeters exist","Implementation is a multi-year journey requiring process and culture change","It instantly secures legacy applications without any integration effort"], correct:2, explanation:"Zero Trust is a gradual journey requiring sustained effort; it is not cloud-only nor an instant fix, and identity remains central." },
  { id:60136, domain:1, level:3, question:"Which is a myth about Zero Trust rather than an accurate description?", options:["Zero Trust verifies each request using identity, device, and context","Zero Trust applies least privilege and assumes the network is hostile","Zero Trust treats internal and external requests with equal scrutiny","Zero Trust means the organization trusts no one and blocks all access"], correct:3, explanation:"Zero Trust is not about blocking everyone; it grants verified, appropriate access. The other statements describe it correctly." },
  { id:60137, domain:1, level:1, question:"What is the relationship between Zero Trust and microsegmentation?", options:["Microsegmentation is a technique that helps enforce Zero Trust boundaries","Microsegmentation is the opposite of Zero Trust and weakens its controls","Microsegmentation and Zero Trust are unrelated and never used together","Microsegmentation replaces the need for identity in Zero Trust designs"], correct:0, explanation:"Microsegmentation enforces fine-grained boundaries supporting Zero Trust; it complements rather than opposes or replaces identity controls." },
  { id:60138, domain:1, level:2, question:"In Zero Trust, when should access to a resource be re-evaluated?", options:["Only at the moment of the very first successful authentication event","Continuously, as context and risk signals change during the session","Once per calendar day during a scheduled overnight batch job run","Never, since revalidation adds unnecessary load on the access gateway"], correct:1, explanation:"Zero Trust re-evaluates access continuously based on changing context; one-time or daily checks leave windows of stale trust." },
  { id:60139, domain:1, level:2, question:"Which describes the shift Zero Trust makes regarding 'trust but verify'?", options:["It strengthens 'trust but verify' by trusting more entities up front","It keeps 'trust but verify' but applies it only to external partners","It replaces 'trust but verify' with 'never trust, always verify' as the default","It abandons verification entirely in favor of stronger perimeter trust"], correct:2, explanation:"Zero Trust flips the old 'trust but verify' to 'never trust, always verify,' removing default trust rather than expanding it." },
  { id:60140, domain:1, level:3, question:"Why is location-based trust considered insufficient in modern environments?", options:["Network locations are now permanently fixed and easy to fully secure","All modern traffic is unencrypted, making location the only usable signal","Regulators forbid the use of any network segmentation whatsoever","Cloud, mobile, and remote work dissolve the clear network boundary"], correct:3, explanation:"Cloud and remote work erode the perimeter, so location no longer indicates trust; Zero Trust verifies identity and context instead." },
  { id:60141, domain:1, level:1, question:"What does Zero Trust assume about the network by default?", options:["The network is hostile and may already contain malicious actors","The internal network is inherently safe once the firewall is in place","The network can be fully trusted after a single penetration test passes","The network only needs protection at its external internet boundary"], correct:0, explanation:"Zero Trust treats the network as hostile and potentially compromised; it does not assume internal safety based on a firewall or test." },
  { id:60142, domain:1, level:2, question:"Which scenario best illustrates the principle of least privilege?", options:["A support agent is granted domain administrator rights for convenience","A support agent can read tickets but cannot access the payroll database","Every employee shares one account with full access to all systems","Contractors receive the same broad access as full-time senior staff"], correct:1, explanation:"Least privilege gives the agent only what the job needs; the other options grant excessive or shared access, violating the principle." },
  { id:60143, domain:1, level:2, question:"An organization grants a new app access to only the one database it needs. Which principle is this?", options:["Assume breach, treating the app as already compromised by default","Continuous verification, re-checking the app's identity every minute","Least privilege, limiting the app to exactly the access it requires","Defense-in-depth, layering multiple independent security controls"], correct:2, explanation:"Restricting the app to only the database it needs is least privilege; the other principles describe different Zero Trust ideas." },
  { id:60144, domain:1, level:3, question:"A firewall lets any device on the VLAN reach all servers. Which Zero Trust principle does this violate?", options:["It violates encryption-in-transit by exposing data on the wire","It violates continuous logging by failing to record the connections","It violates MFA by skipping a second authentication factor","It violates least privilege by granting broad implicit network access"], correct:3, explanation:"Allowing broad reach based on VLAN membership grants excessive implicit access, violating least privilege and location-based trust removal." },
  { id:60145, domain:1, level:1, question:"Which best explains why 'assume breach' changes monitoring strategy?", options:["Teams monitor internal activity closely, not just the network perimeter","Teams stop monitoring entirely since breaches are assumed inevitable","Teams monitor only outbound traffic toward external cloud providers","Teams monitor only the firewall logs and ignore endpoint telemetry"], correct:0, explanation:"Assume breach drives internal and endpoint monitoring to detect attackers already inside, not just perimeter watching." },
  { id:60146, domain:1, level:2, question:"In a Zero Trust architecture, what is the policy engine's primary function?", options:["To physically route packets between segmented network microperimeters","To make the ultimate decision to grant, deny, or revoke access to a resource","To store the long-term encryption keys used for data-at-rest protection","To distribute software patches to endpoints based on posture findings"], correct:1, explanation:"The policy engine decides on access; routing, key storage, and patching are separate functions handled elsewhere." },
  { id:60147, domain:1, level:2, question:"What signals might a trust algorithm consider before granting access?", options:["Only the source IP address of the connection and nothing else at all","Only whether the request arrived during normal business working hours","User identity, device posture, resource sensitivity, and behavioral context","Only the size in bytes of the data the subject intends to transfer"], correct:2, explanation:"Trust algorithms weigh many signals (identity, device, sensitivity, behavior); relying on a single factor like IP or time is inadequate." },
  { id:60148, domain:1, level:3, question:"How does Zero Trust treat north-south versus east-west traffic?", options:["Only north-south traffic is verified while east-west is implicitly trusted","Only east-west traffic is verified while north-south is ignored entirely","Neither direction is verified once the device joins the trusted domain","Both directions are subject to verification rather than only the perimeter"], correct:3, explanation:"Zero Trust verifies traffic in all directions; traditional models scrutinize north-south while trusting east-west by default." },
  { id:60149, domain:1, level:1, question:"Which statement about Zero Trust and encryption is most accurate?", options:["Encryption supports Zero Trust but does not replace identity-based verification","Encryption alone fully implements Zero Trust without any access policy","Zero Trust forbids encryption because it hides traffic from inspection","Encryption is needed only on the perimeter firewall and nowhere else"], correct:0, explanation:"Encryption is a supporting control; Zero Trust still requires identity-centric verification and policy enforcement beyond encryption." },
  { id:60150, domain:1, level:2, question:"Why is 'identity as the control plane' significant for cloud-era security?", options:["Identity changes with every packet, making it the easiest thing to track","Identity is consistent across locations, unlike a fixed network perimeter","Identity is only relevant for on-premises Active Directory deployments","Identity removes the need to assess device posture or user behavior"], correct:1, explanation:"Identity travels with the subject across clouds and locations, making it a stable control plane where the network perimeter no longer is." },
  { id:60151, domain:1, level:2, question:"A user authenticates successfully but their device fails a compliance check. What should Zero Trust do?", options:["Grant full access since the user identity was verified successfully","Grant access and ignore the device because identity outranks devices","Deny or limit access because device posture is part of the trust decision","Grant access permanently and schedule a device review for next year"], correct:2, explanation:"Device posture is a required signal; a failed check should reduce or deny access even with a valid identity." },
  { id:60152, domain:1, level:3, question:"Which best describes the migration approach most experts recommend for Zero Trust?", options:["A single overnight cutover replacing all existing controls at once","Buying one vendor's suite that instantly delivers full Zero Trust maturity","Focusing only on the perimeter firewall while leaving internal trust intact","Incremental, protecting one protect surface at a time and expanding outward"], correct:3, explanation:"Zero Trust is best adopted incrementally, securing protect surfaces one at a time; big-bang or single-product approaches are unrealistic." },
  { id:60153, domain:1, level:1, question:"In Zero Trust, what happens to trust after a session is granted?", options:["It remains conditional and can be revoked if signals indicate higher risk","It becomes permanent for the life of the user's account credentials","It transfers automatically to any other device the same user owns","It is locked in until the next scheduled annual access certification"], correct:0, explanation:"Granted trust stays conditional and revocable based on changing signals; it is not permanent or transferable." },
  { id:60154, domain:1, level:2, question:"What is the main weakness of the 'castle-and-moat' security model?", options:["It encrypts too much traffic, slowing down legitimate internal users","Once inside the moat, attackers move freely with little further checking","It verifies every internal request, creating excessive user friction","It applies least privilege so strictly that productivity collapses"], correct:1, explanation:"Castle-and-moat trusts insiders, letting attackers roam after breaching the perimeter; Zero Trust addresses exactly this gap." },
  { id:60155, domain:1, level:2, question:"Which is an accurate statement about Zero Trust and trust levels?", options:["Trust, once earned through MFA, is granted permanently to the subject","Trust is a binary set at login and never adjusted during the session","Trust is never permanent and is always conditional on current context","Trust is assigned by network zone and stays fixed for that zone"], correct:2, explanation:"Zero Trust treats trust as conditional and continuously re-assessed, never permanent or zone-fixed." },
  { id:60156, domain:1, level:3, question:"How does Zero Trust change the default network posture for a new connection?", options:["The default is allow, and only known-bad traffic is explicitly blocked","The default is allow for internal subnets and deny for external ones","The default depends solely on whether the port number is well known","The default is deny, and access must be explicitly granted by policy"], correct:3, explanation:"Zero Trust uses default-deny with explicit, policy-based allow; allow-by-default or subnet-based defaults reintroduce implicit trust." },
  { id:60157, domain:1, level:1, question:"What does the BeyondCorp model notably remove reliance on?", options:["The privileged internal network as a basis for granting access","Multi-factor authentication for accessing internal applications","Centralized identity providers for authenticating corporate users","Endpoint device certificates issued by the corporate authority"], correct:0, explanation:"BeyondCorp shifts access decisions away from the internal network to identity and device trust, so being on the LAN grants nothing." },
  { id:60158, domain:1, level:2, question:"Which describes a correct understanding of the Zero Trust 'journey'?", options:["Maturity is reached the moment a Zero Trust product is installed","Maturity grows over time across pillars rather than being achieved instantly","Maturity applies to identity only and not to devices or data","Maturity is a one-time certification that never needs revisiting"], correct:1, explanation:"Zero Trust maturity develops incrementally across all pillars over time; it is not an instant or one-time achievement." },
  { id:60159, domain:1, level:2, question:"Why does Zero Trust scrutinize east-west traffic so heavily?", options:["East-west traffic is always unencrypted and therefore easy to read","East-west traffic never crosses any firewall and so is invisible","Lateral movement between internal systems is a primary attacker technique","East-west traffic is the only traffic that ever carries sensitive data"], correct:2, explanation:"Attackers pivot laterally (east-west) after initial access; scrutinizing this traffic limits their movement." },
  { id:60160, domain:1, level:3, question:"Which is the best example of eliminating implicit trust?", options:["Allowing any domain-joined machine to reach the file server freely","Trusting all traffic that originates from the corporate IP range","Permitting unauthenticated access within the data center subnet","Requiring authorization for an internal server even from an on-LAN host"], correct:3, explanation:"Requiring authorization even for on-LAN hosts removes implicit trust; the other options grant trust based on location or domain membership." },
  { id:60161, domain:1, level:1, question:"A policy grants access only after checking identity, device, and time-of-day risk. This exemplifies what?", options:["Dynamic, context-aware access decisions central to Zero Trust","Static access control lists configured once on the perimeter firewall","Implicit trust extended to anything inside the network boundary","A one-time authentication check performed only at session start"], correct:0, explanation:"Using multiple real-time signals for each decision is dynamic, context-aware access; the alternatives are static or implicit." },
  { id:60162, domain:1, level:2, question:"What is the relationship between Zero Trust and single sign-on (SSO)?", options:["SSO fully implements Zero Trust by itself once it is deployed","SSO can support Zero Trust identity verification but is not the whole model","SSO contradicts Zero Trust because it reduces authentication events","SSO is irrelevant to Zero Trust and should be removed when adopting it"], correct:1, explanation:"SSO is a useful identity component but does not by itself constitute Zero Trust, which also requires continuous, contextual authorization." },
  { id:60163, domain:1, level:2, question:"Which is a true statement about Zero Trust and insider threats?", options:["Zero Trust ignores insiders because they are already trusted employees","Zero Trust assumes insiders are always benign and focuses only outward","By removing implicit internal trust, Zero Trust reduces insider abuse risk","Zero Trust grants insiders broad access to maximize their productivity"], correct:2, explanation:"Zero Trust treats insiders with the same scrutiny as outsiders, limiting the damage a malicious or compromised insider can do." },
  { id:60164, domain:1, level:3, question:"What is the primary purpose of defining a protect surface first?", options:["To enumerate every internet-facing port for the firewall to block","To replace the need for any identity or device verification later","To document all employee job titles for access certification audits","To focus controls precisely on what truly matters before expanding"], correct:3, explanation:"Defining the protect surface focuses controls on critical DAAS; it does not replace identity controls or merely list ports." },
  { id:60165, domain:1, level:1, question:"Which statement correctly distinguishes authentication from authorization in Zero Trust?", options:["Authentication proves who a subject is; authorization decides what it may do","Authentication decides what a subject may do; authorization proves identity","Both terms mean the same thing and are used interchangeably in policy","Authentication applies to devices while authorization applies to networks"], correct:0, explanation:"Authentication establishes identity; authorization grants specific access. Zero Trust requires both, continuously." },
  { id:60166, domain:1, level:2, question:"Why is continuous authentication preferred over a single login event?", options:["A single login is impossible to perform securely on modern devices","Risk and context can change after login, requiring ongoing re-evaluation","Continuous authentication removes the need for any password at all","Login events cannot be logged, so continuous checks replace logging"], correct:1, explanation:"Conditions change after login, so continuous authentication catches new risk; a one-time check leaves gaps." },
  { id:60167, domain:1, level:2, question:"Which option best reflects the Zero Trust view of the 'trusted internal network'?", options:["The internal network remains the most trusted zone once firewalled","Only the data center subnet is trusted while user subnets are not","There is no inherently trusted network; trust is established per request","The network becomes trusted automatically after passing a vuln scan"], correct:2, explanation:"Zero Trust holds that no network is inherently trusted; trust is established per request regardless of segment." },
  { id:60168, domain:1, level:3, question:"An attacker compromises one workstation but cannot reach the database server. Which design likely prevented this?", options:["A perimeter firewall that only inspects inbound internet traffic","A flat network that trusts all internal hosts equally by default","An implicit trust zone covering the entire corporate subnet range","Microsegmentation enforcing least-privilege paths between systems"], correct:3, explanation:"Microsegmentation with least-privilege paths blocks lateral movement to the database; flat networks and implicit zones would not." },
  { id:60169, domain:1, level:1, question:"Which is the most accurate description of Zero Trust as a concept?", options:["A strategic approach and set of principles, not a single specific technology","A specific firewall appliance that must be installed at the network edge","A compliance checklist that, once completed, certifies an organization","A protocol that encrypts all traffic between clients and servers"], correct:0, explanation:"Zero Trust is a strategy and set of principles, not a product, checklist, or protocol." },
  { id:60170, domain:1, level:2, question:"Why does Zero Trust apply verification to service-to-service (machine) communication?", options:["Services never need authentication because they run inside the data center","Services can be compromised and used to move laterally just like users","Services are inherently trusted once their host joins the domain","Services communicate only north-south and so pose no lateral risk"], correct:1, explanation:"Machine identities can be abused for lateral movement, so Zero Trust verifies service-to-service traffic, not just user access." },
  { id:60171, domain:1, level:2, question:"Which best captures the difference between Zero Trust and a flat network?", options:["Zero Trust and a flat network both isolate every host by default","A flat network verifies every request while Zero Trust trusts insiders","Zero Trust segments and verifies; a flat network lets hosts reach each other freely","Both rely solely on a single perimeter firewall for all decisions"], correct:2, explanation:"A flat network allows free host-to-host reach; Zero Trust segments and verifies, limiting lateral movement." },
  { id:60172, domain:1, level:3, question:"What does 'reducing the blast radius' mean in a Zero Trust context?", options:["Decreasing the physical size of the corporate data center footprint","Lowering the encryption strength to improve overall network speed","Expanding implicit trust so fewer authentication checks are needed","Limiting how far an attacker can spread after compromising one element"], correct:3, explanation:"Reducing blast radius means containing an attacker to a small area through segmentation and least privilege." },
  { id:60173, domain:1, level:1, question:"Which is a correct statement about Zero Trust and compliance frameworks?", options:["Zero Trust can support compliance but is not itself a compliance standard","Achieving Zero Trust automatically satisfies all regulatory requirements","Zero Trust replaces the need to follow any compliance framework","Compliance frameworks prohibit organizations from adopting Zero Trust"], correct:0, explanation:"Zero Trust supports many compliance goals but is an architecture, not a compliance standard, and does not automatically satisfy regulations." },
  { id:60174, domain:1, level:2, question:"In Zero Trust, why is visibility considered a cross-cutting capability?", options:["Visibility applies only to the network pillar and nothing else","Decisions and detection across every pillar depend on rich telemetry","Visibility is optional and only useful during annual security audits","Visibility replaces the need for identity and device verification"], correct:1, explanation:"Visibility and analytics feed decisions and detection across all pillars, making it a cross-cutting capability." },
  { id:60175, domain:1, level:2, question:"Why is automation important to a mature Zero Trust program?", options:["It removes the need for any human governance of the architecture","It eliminates the requirement to ever log or monitor access events","It enables fast, consistent policy enforcement and response at scale","It permanently grants trust so policies never need re-evaluation"], correct:2, explanation:"Automation enables scalable, consistent enforcement and rapid response; it does not remove governance, logging, or re-evaluation." },
  { id:60176, domain:1, level:3, question:"Which is the best description of governance as a Zero Trust cross-cutting capability?", options:["Encrypting all data at rest within the central corporate database","Routing traffic between microperimeters using dynamic protocols","Issuing device certificates from the internal certificate authority","Defining and overseeing the policies and accountability across all pillars"], correct:3, explanation:"Governance establishes and oversees policies and accountability across pillars; the others are specific technical functions." },
  { id:60177, domain:1, level:1, question:"A company allows access only from compliant, managed devices. This reflects which pillar?", options:["The Devices pillar, which assesses endpoint posture before access","The Data pillar, which classifies and protects information assets","The Networks pillar, which segments and inspects traffic flows","The Identity pillar, which authenticates and authorizes subjects"], correct:0, explanation:"Requiring compliant managed devices is a Devices-pillar control assessing endpoint posture." },
  { id:60178, domain:1, level:2, question:"Tagging data by sensitivity and restricting access accordingly relates to which pillar?", options:["The Devices pillar, which evaluates the posture of endpoints","The Data pillar, which classifies and protects information assets","The Networks pillar, which segments and monitors traffic","The Identity pillar, which manages authentication of users"], correct:1, explanation:"Classifying data by sensitivity and gating access is a Data-pillar activity." },
  { id:60179, domain:1, level:2, question:"Microsegmenting traffic and inspecting flows between workloads maps to which pillar?", options:["The Identity pillar, which authenticates and authorizes subjects","The Data pillar, which labels and encrypts stored information","The Networks pillar, which segments and inspects internal traffic","The Applications pillar, which secures workload runtime behavior"], correct:2, explanation:"Microsegmentation and traffic inspection are Networks-pillar controls." },
  { id:60180, domain:1, level:3, question:"Securing how an application authorizes requests at runtime maps to which pillar?", options:["The Networks pillar, governing segmentation and traffic flow between internal subnets","The Devices pillar, governing the posture of user endpoints","The Data pillar, governing classification of stored records","The Applications and Workloads pillar, governing app-level access controls"], correct:3, explanation:"Application-level authorization and runtime security fall under the Applications & Workloads pillar." },
  { id:60181, domain:1, level:1, question:"Which statement about the seven NIST tenets is accurate?", options:["All data sources and computing services are treated as resources to protect","Only servers in the data center are considered protected resources","Trust is granted permanently once the network connection is encrypted","Access is granted based solely on the source network location"], correct:0, explanation:"A NIST tenet states that all data sources and computing services are resources; the others contradict the tenets." },
  { id:60182, domain:1, level:2, question:"According to NIST tenets, how should each access request be evaluated?", options:["Once at onboarding and then trusted for the account's lifetime","On a per-session basis using dynamic policy and observable signals","Based only on whether the device is joined to the corporate domain","Based only on the time of day the request happens to be made"], correct:1, explanation:"NIST calls for per-session, dynamic, policy-driven evaluation using multiple signals, not one-time or single-factor checks." },
  { id:60183, domain:1, level:2, question:"Which NIST tenet addresses the integrity and security posture of assets?", options:["The organization trusts all owned assets without ongoing measurement","The organization checks asset posture only during annual audits","The organization monitors and measures the integrity and posture of assets","The organization ignores asset posture in favor of network location"], correct:2, explanation:"A NIST tenet requires continuously monitoring asset integrity and security posture to inform access decisions." },
  { id:60184, domain:1, level:3, question:"How does Zero Trust treat the concept of a one-time strong login?", options:["It is sufficient on its own to satisfy all Zero Trust requirements","It is unnecessary because device posture alone determines trust","It is forbidden because authentication adds friction for users","It is necessary but insufficient because trust must be continually reassessed"], correct:3, explanation:"A strong login helps but is insufficient; Zero Trust requires continuous reassessment of trust throughout the session." },
  { id:60185, domain:1, level:1, question:"Which is a key reason perimeter-only security fails in cloud environments?", options:["Resources live outside the traditional perimeter, dissolving its boundary","Cloud providers forbid the use of any identity verification at all","Cloud traffic is always trusted automatically by every firewall","Perimeters in the cloud are far easier to define than on-premises"], correct:0, explanation:"Cloud resources sit outside any fixed perimeter, so perimeter-only security cannot protect them; Zero Trust verifies per request instead." },
  { id:60186, domain:1, level:2, question:"What is the most accurate view of Zero Trust and user experience?", options:["Zero Trust always forces users to re-enter passwords on every single click","Well-designed Zero Trust can be largely transparent to legitimate users","Zero Trust makes legitimate access impossible to streamline at all","Zero Trust removes all authentication, so users notice nothing ever"], correct:1, explanation:"Good Zero Trust design uses context and SSO to stay mostly transparent; it does not require constant friction or remove authentication." },
  { id:60187, domain:1, level:2, question:"Which describes the correct handling of legacy systems under Zero Trust?", options:["They are exempt from Zero Trust and trusted because they are internal","They must be deleted immediately before Zero Trust can begin at all","They are often wrapped with proxies or gateways to apply Zero Trust controls","They automatically support Zero Trust without any integration work"], correct:2, explanation:"Legacy systems are commonly fronted by proxies or gateways to enforce Zero Trust; they are neither exempt nor instantly compatible." },
  { id:60188, domain:1, level:3, question:"Why does Zero Trust emphasize knowing the transaction flows of the protect surface?", options:["Mapping flows is required to disable all encryption between systems","Mapping flows replaces the need for any identity verification later","Knowing flows lets administrators grant universal access more quickly","Understanding flows lets policy be written precisely around real access needs"], correct:3, explanation:"Mapping transaction flows informs precise least-privilege policy around the protect surface; it does not replace identity controls." },
  { id:60189, domain:1, level:1, question:"Which best describes a Zero Trust policy enforcement point (PEP)?", options:["A component that allows, monitors, and terminates connections per policy","A database that stores all historical user authentication records","A dashboard that visualizes analytics for the security operations team","A certificate authority that issues device identity certificates"], correct:0, explanation:"The PEP enforces decisions by allowing, monitoring, or terminating connections; the others are unrelated components." },
  { id:60190, domain:1, level:2, question:"How does the principle 'never trust, always verify' apply to a returning, known user?", options:["The user is trusted automatically because they were verified before","The user is re-verified each session because prior trust does not persist","The user is trusted as long as they connect from the same office","The user is exempt from verification after their tenth successful login"], correct:1, explanation:"Even known users are re-verified each session; prior verification does not grant lasting trust." },
  { id:60191, domain:1, level:2, question:"Which is a correct statement about Zero Trust and the principle of segmentation?", options:["Coarser segmentation improves Zero Trust by simplifying all firewall rules","Segmentation is irrelevant because identity alone stops lateral movement","Finer segmentation generally reduces the paths available for lateral movement","Segmentation only matters for north-south internet-facing connections"], correct:2, explanation:"Finer-grained segmentation reduces lateral movement paths; coarse segmentation and ignoring east-west traffic weaken the model." },
  { id:60192, domain:1, level:3, question:"What does Zero Trust recommend regarding standing privileges?", options:["Maximize standing privileges so users never face access delays","Grant permanent administrator rights to all technical staff members","Keep all privileges static and review them only every few years","Minimize standing privileges, favoring just-in-time and just-enough access"], correct:3, explanation:"Zero Trust favors just-in-time, just-enough access and minimizing standing privileges to limit exposure." },
  { id:60193, domain:1, level:1, question:"Which scenario shows Zero Trust applied to a third-party contractor?", options:["The contractor gets scoped, time-limited access only to needed resources","The contractor receives the same broad network access as employees","The contractor is trusted fully once connected through the corporate VPN","The contractor's access is never reviewed once initially provisioned"], correct:0, explanation:"Scoped, time-limited least-privilege access reflects Zero Trust; broad or unreviewed access does not." },
  { id:60194, domain:1, level:2, question:"Why is 'Zero Trust equals no trust' an inaccurate characterization?", options:["Trust is never granted to anyone under any circumstances at all","Trust is granted, but only after verification and only as much as needed","Trust is granted broadly but only to internal corporate users","Trust is unrelated to access decisions in a Zero Trust model"], correct:1, explanation:"Zero Trust grants appropriate, verified trust per request; it does not mean denying all trust outright." },
  { id:60195, domain:1, level:2, question:"Which describes how Zero Trust handles a device that becomes non-compliant mid-session?", options:["Access continues unchanged because it was granted at session start","Access is unaffected since device posture is checked only once","Access can be reduced or revoked in response to the changed posture","Access is escalated to admin level to allow remediation by the user"], correct:2, explanation:"Continuous evaluation lets Zero Trust reduce or revoke access when device posture degrades mid-session." },
  { id:60196, domain:1, level:3, question:"What is the relationship between Zero Trust and the principle of explicit verification?", options:["Explicit verification contradicts Zero Trust by adding extra checks","Explicit verification applies only to external users, never internal ones","Explicit verification is replaced by implicit trust within the LAN","Explicit verification using available signals is a core Zero Trust principle"], correct:3, explanation:"Verifying explicitly with all available data points is foundational to Zero Trust, not contradictory to it." },
  { id:60197, domain:1, level:1, question:"Which statement about Zero Trust adoption maturity is accurate?", options:["Organizations typically progress through traditional, advanced, and optimal stages","Organizations either possess Zero Trust capability fully or do not have any of it at all","Maturity is measured only by the number of firewalls deployed","Maturity is achieved instantly by purchasing a Zero Trust appliance"], correct:0, explanation:"Maturity models describe progression (e.g., traditional to advanced to optimal); Zero Trust is not all-or-nothing or instant." },
  { id:60198, domain:1, level:2, question:"How should access decisions account for resource sensitivity in Zero Trust?", options:["All resources are treated identically regardless of their sensitivity","More sensitive resources warrant stricter verification and tighter policy","Only public resources require verification under the Zero Trust model","Sensitivity is irrelevant once a user has authenticated successfully"], correct:1, explanation:"Zero Trust scales scrutiny with sensitivity; more critical resources get stricter controls." },
  { id:60199, domain:1, level:2, question:"Which is a correct understanding of Zero Trust and remote work?", options:["Remote users are trusted more because they use company-issued laptops","On-site users are exempt from verification while remote users are not","Remote and on-site users are subject to the same per-request verification","Remote work makes Zero Trust unnecessary because of VPN encryption"], correct:2, explanation:"Zero Trust treats remote and on-site access identically, verifying every request regardless of location." },
  { id:60200, domain:1, level:3, question:"What is the purpose of mapping who needs access to what in Zero Trust?", options:["To eliminate the need for ongoing authentication of those users","To grant the broadest possible access to maximize productivity","To justify removing segmentation between internal network zones","To craft precise least-privilege policies around the protect surface"], correct:3, explanation:"Mapping access needs supports precise least-privilege policy; it does not justify broad access or removing segmentation." },
  { id:60201, domain:1, level:1, question:"Which best explains why Zero Trust is described as 'data-centric'?", options:["Protecting the data and resources that matter drives the architecture","Only the data center's physical security is addressed by the model","Data is the only pillar; identity and devices are not considered","The model centers on perimeter data flows entering from the internet"], correct:0, explanation:"Zero Trust is data-centric in that protecting critical data/resources (the protect surface) drives controls across all pillars." },
  { id:60202, domain:1, level:2, question:"A request from a trusted user on an unknown personal device is evaluated how in Zero Trust?", options:["The trusted user identity alone grants full access to all resources","The unknown device lowers trust, so access may be limited or denied","The request is auto-approved because the user passed MFA before","The device is ignored because identity always overrides device signals"], correct:1, explanation:"An unmanaged device reduces the trust score, so Zero Trust may limit or deny access even for a known user." },
  { id:60203, domain:1, level:2, question:"Which describes the correct ordering when designing a Zero Trust deployment?", options:["Buy the product, install it, and Zero Trust is immediately complete","Configure the perimeter firewall, then trust everything behind it","Define the protect surface, map flows, build the architecture, then policy","Grant broad access first, then remove privileges only after incidents"], correct:2, explanation:"A common method defines the protect surface, maps transaction flows, builds the architecture, then writes policy." },
  { id:60204, domain:1, level:3, question:"Why is Zero Trust often described as 'identity-centric' rather than 'network-centric'?", options:["Access hinges on the subnet a device happens to connect from","Access hinges entirely on perimeter firewall rules and port numbers","Access hinges only on whether traffic is encrypted in transit","Access hinges on verified identity and context, not on network position"], correct:3, explanation:"Zero Trust bases decisions on identity and context rather than network position, hence identity-centric." },
  { id:60205, domain:1, level:1, question:"Which is an accurate statement about Zero Trust and trust zones?", options:["Zero Trust shrinks implicit trust zones toward individual resources","Zero Trust enlarges implicit trust zones to cover whole subnets","Zero Trust keeps one large trust zone around the corporate campus","Zero Trust trusts any zone protected by a perimeter firewall"], correct:0, explanation:"Zero Trust shrinks implicit trust zones as close to individual resources as possible, ideally to per-request decisions." },
  { id:60206, domain:1, level:2, question:"How does Zero Trust view the statement 'we have a firewall, so we are secure'?", options:["As completely accurate for any modern enterprise network design","As insufficient, because a firewall does not stop internal lateral movement","As true only if the firewall also encrypts all internal traffic","As true provided the firewall is from a next-generation vendor"], correct:1, explanation:"A firewall alone leaves internal trust intact and does not stop lateral movement; Zero Trust requires more than perimeter controls." },
  { id:60207, domain:1, level:2, question:"Which is the best description of a Zero Trust 'policy administrator'?", options:["The database that stores every historical access decision for later compliance audits","The analyst who manually approves each individual access request","The component that establishes or terminates the connection per the engine's decision","The firewall that performs deep packet inspection at the edge"], correct:2, explanation:"In NIST's model, the policy administrator executes the policy engine's decision to set up or tear down access." },
  { id:60208, domain:1, level:3, question:"What is the relationship between the policy engine and policy administrator in NIST's model?", options:["The administrator decides and the engine merely logs the outcome","Both are identical roles performed by the same physical firewall","The engine encrypts traffic while the administrator routes packets","The engine decides and the administrator carries out that decision"], correct:3, explanation:"The policy engine makes the access decision; the policy administrator implements it. Together they form the policy decision point." },
  { id:60209, domain:1, level:1, question:"Which is a misconception about Zero Trust and productivity?", options:["Zero Trust must always slow users down with constant manual approvals","Zero Trust can use context to grant low-friction access to low-risk requests","Zero Trust applies stricter checks only when risk signals increase","Zero Trust can leverage SSO to reduce repeated credential prompts"], correct:0, explanation:"It is a myth that Zero Trust always hurts productivity; risk-based, contextual access can keep low-risk flows smooth." },
  { id:60210, domain:1, level:2, question:"Why does Zero Trust treat all data sources and services as resources to be protected?", options:["Only databases hold value, so other services need no protection","Any service can hold or expose sensitive data and can be attacked","Services inside the data center cannot be reached by attackers","Protecting all services removes the need to authenticate users"], correct:1, explanation:"A NIST tenet treats every data source and service as a protectable resource because any can be targeted or expose data." },
  { id:60211, domain:1, level:2, question:"Which best describes how Zero Trust handles a successful phishing attack that steals a password?", options:["The stolen password grants complete access because the supplied identity is technically valid","Zero Trust cannot help because authentication already succeeded","Additional signals like device and behavior can still block misuse of the password","The attacker gains permanent trust once the password is accepted"], correct:2, explanation:"Zero Trust's reliance on multiple signals (device, behavior, MFA) can detect and block misuse even when a password is stolen." },
  { id:60212, domain:1, level:3, question:"Which is an accurate description of the 'assume breach' posture toward logging?", options:["Logging is optional because the perimeter is assumed to be impenetrable","Logging only outbound internet traffic is sufficient under this posture","Logging can be disabled once microperimeters are fully deployed","Detailed logging is essential to detect attackers presumed already inside"], correct:3, explanation:"Assume breach demands rich logging and visibility to detect adversaries presumed already present." },
  { id:60213, domain:1, level:1, question:"What is the recommended approach to trust for newly onboarded internal applications?", options:["They start untrusted and must be explicitly authorized like anything else","They are trusted automatically because they run on internal servers","They inherit broad trust from the subnet they are deployed onto","They are exempt from policy until their first security incident"], correct:0, explanation:"New internal apps start untrusted and require explicit authorization; internal deployment confers no automatic trust." },
  { id:60214, domain:1, level:2, question:"Which statement about Zero Trust and the 'human element' is most accurate?", options:["Zero Trust is purely technical and needs no organizational change","Successful adoption requires culture and process change, not just technology","Zero Trust eliminates the need for any security awareness training","Zero Trust succeeds automatically once the right tools are installed"], correct:1, explanation:"Zero Trust adoption needs cultural and process changes alongside technology; it is not purely a tooling problem." },
  { id:60215, domain:1, level:2, question:"How does Zero Trust handle access for a service account used by an automated job?", options:["It is granted broad standing access since it is not a human user","It is exempt from verification because automation is inherently trusted","It is given least-privilege, verified access scoped to its specific task","It inherits administrator rights to ensure jobs never fail to run"], correct:2, explanation:"Service accounts get scoped least-privilege access and verification just like users; broad or admin access violates Zero Trust." },
  { id:60216, domain:1, level:3, question:"Which is the best description of how Zero Trust treats trust as a function of risk?", options:["Higher risk leads to relaxed checks to keep the user productive","Risk has no bearing on access once the user authenticates","Risk is assessed only for external users and never for insiders","Higher risk leads to stricter verification or denial of the request"], correct:3, explanation:"Zero Trust modulates access by risk, applying stricter controls or denial as risk rises." },
  { id:60217, domain:1, level:1, question:"What does it mean that Zero Trust verification is 'continuous and adaptive'?", options:["Decisions adjust in real time as identity, device, and context evolve","Decisions are fixed at login and adapt only at the next password reset","Decisions adapt only to network bandwidth, not security signals","Decisions are made once per quarter during access recertification"], correct:0, explanation:"Continuous and adaptive verification means decisions change in real time with evolving signals." },
  { id:60218, domain:1, level:2, question:"Which is a correct understanding of Zero Trust and microperimeter placement?", options:["Microperimeters are placed only at the outer edge of the network","Microperimeters are placed as close to the protect surface as possible","Microperimeters replace identity verification near the resource","Microperimeters are placed randomly to confuse potential attackers"], correct:1, explanation:"Microperimeters sit as close to the protect surface as possible to enforce tight, resource-specific controls." },
  { id:60219, domain:1, level:2, question:"How does Zero Trust reduce reliance on the network being the security boundary?", options:["By building a stronger single firewall at the network's outer edge","By trusting any device that successfully joins the internal domain","By tying access to verified identity and context independent of location","By encrypting only the traffic that crosses the perimeter boundary"], correct:2, explanation:"Zero Trust shifts the boundary to identity and context, so being on the network is no longer the basis for access." },
  { id:60220, domain:1, level:3, question:"Which best illustrates 'eliminating location-based trust'?", options:["A user in the office is auto-trusted while remote users must verify","A user on the corporate IP range bypasses all access checks","A user inside the data center subnet reaches any server freely","A user in the headquarters office is verified the same as one at a cafe"], correct:3, explanation:"Verifying the office user identically to a remote one eliminates location-based trust; the others grant trust by location." },
  { id:60221, domain:1, level:1, question:"Why might an organization adopt Zero Trust incrementally by protect surface?", options:["It limits scope and risk while delivering value before expanding further","It allows the perimeter firewall to be removed on the very first day","It guarantees the entire organization is compliant within one week","It avoids the need to ever map transaction flows for any system"], correct:0, explanation:"Incremental, protect-surface-by-protect-surface adoption limits risk and delivers value progressively." },
  { id:60222, domain:1, level:2, question:"Which is the most accurate statement about Zero Trust and 'allow lists' versus 'deny lists'?", options:["Zero Trust favors deny lists, allowing everything not explicitly blocked","Zero Trust favors explicit allow lists with default-deny for everything else","Zero Trust avoids lists entirely and trusts based on network zone","Zero Trust uses deny lists only for external internet-facing traffic"], correct:1, explanation:"Zero Trust uses default-deny with explicit allow lists, the opposite of allowing all but known-bad." },
  { id:60223, domain:1, level:2, question:"Which describes a correct relationship between Zero Trust and continuous monitoring?", options:["Monitoring is performed once and then access is fixed permanently","Monitoring is unnecessary once strong authentication is in place","Monitoring feeds the signals that drive ongoing access decisions","Monitoring covers only the perimeter and ignores internal activity"], correct:2, explanation:"Continuous monitoring supplies the telemetry that informs ongoing, adaptive access decisions across the environment." },
  { id:60224, domain:1, level:3, question:"What is a key reason Zero Trust verifies devices in addition to users?", options:["Devices never carry malware once they are joined to the domain","Verifying users alone fully prevents all forms of credential theft","Device verification replaces the need to authenticate the user","A compromised device can abuse a legitimate user's valid credentials"], correct:3, explanation:"Even with valid credentials, a compromised device poses risk, so Zero Trust verifies device posture alongside identity." },
  { id:60225, domain:1, level:1, question:"Which is the best description of Zero Trust's stance on broad VPN access?", options:["It is discouraged because it often grants wide implicit network access","It is required because all Zero Trust verification happens in the tunnel","It is preferred over per-resource access for simplicity of management","It is equivalent to Zero Trust as long as the tunnel is encrypted"], correct:0, explanation:"Broad VPN access grants wide implicit reach, contrary to Zero Trust's per-resource, least-privilege approach." },
  { id:60226, domain:1, level:2, question:"How does Zero Trust apply to communication between two microservices?", options:["Calls between internal services are trusted to reduce latency overhead","Each call is authenticated and authorized rather than implicitly trusted","Only calls leaving the cluster are verified; internal calls are trusted","Service-to-service calls are exempt because they use private addresses"], correct:1, explanation:"Zero Trust authenticates and authorizes service-to-service calls; private addressing or internal location does not confer trust." },
  { id:60227, domain:1, level:2, question:"Which statement reflects an accurate benefit of Zero Trust for breach containment?", options:["A single breach automatically compromises the entire flat network","Breaches are made impossible once microperimeters are in place","Compromise of one segment is less likely to cascade across the environment","Containment is achieved by trusting all internal segments equally"], correct:2, explanation:"Segmentation and least privilege contain breaches to small areas; Zero Trust does not make breaches impossible but limits cascade." },
  { id:60228, domain:1, level:3, question:"Why is the phrase 'trust is a vulnerability' associated with Zero Trust?", options:["Trust is a software bug that vendors patch in every release cycle","Trust refers to expired certificates that must be renewed promptly","Trust describes unencrypted traffic that attackers can read freely","Implicit trust is something attackers exploit to move and escalate"], correct:3, explanation:"The idea is that implicit trust is exploited by attackers; removing it (Zero Trust) closes that avenue." },
  { id:60229, domain:1, level:1, question:"Which best describes how Zero Trust treats the boundary between dev and prod environments?", options:["Access between them is segmented and explicitly authorized, not assumed","Dev and prod share one trust zone for engineering convenience","Prod implicitly trusts dev because they belong to the same company","The boundary is enforced only by naming conventions, not by policy"], correct:0, explanation:"Zero Trust segments dev and prod and requires explicit authorization for cross-environment access rather than assuming trust." },
  { id:60230, domain:1, level:2, question:"What does Zero Trust recommend about access reviews and re-certification?", options:["Access should be granted once and never revisited to save effort","Access should be regularly reviewed and reduced as needs change","Access reviews are needed only for external contractor accounts","Access should expand automatically over time as tenure increases"], correct:1, explanation:"Regular review and reduction of access aligns with least privilege; static or expanding access does not." },
  { id:60231, domain:1, level:2, question:"Which is an accurate statement about Zero Trust and the cloud shared-responsibility model?", options:["Zero Trust shifts all responsibility for security onto the cloud provider","Zero Trust is incompatible with the cloud shared-responsibility model","Zero Trust principles apply to the customer's portion of cloud responsibility","Zero Trust applies only to the provider's underlying infrastructure"], correct:2, explanation:"Customers apply Zero Trust to their share of cloud responsibility (identities, configs, data); the provider secures the underlying layers." },
  { id:60232, domain:1, level:3, question:"How does Zero Trust regard the assumption that internal traffic is safe?", options:["It accepts the assumption to reduce overhead on internal links","It accepts it only for traffic between two domain-joined machines","It accepts it for traffic that stays within a single VLAN segment","It rejects the assumption and inspects internal traffic like any other"], correct:3, explanation:"Zero Trust rejects the notion that internal traffic is inherently safe and verifies it like external traffic." },
  { id:60233, domain:1, level:1, question:"Which scenario best demonstrates 'per-request' authorization?", options:["Each attempt to open a file triggers a fresh policy evaluation","One login at 9am authorizes all file access for the entire day","Authorization is decided by the user's VLAN at connection time","Authorization is granted for a week after a single successful MFA"], correct:0, explanation:"Evaluating policy on each file-open attempt is per-request authorization; the others grant durable, non-per-request access." },
  { id:60234, domain:1, level:2, question:"Why does Zero Trust consider behavioral analytics useful?", options:["Behavior is irrelevant once a user passes multi-factor authentication","Anomalous behavior can signal compromise even with valid credentials","Behavioral analytics replace the need for any device posture checks","Behavior is monitored only at the perimeter for inbound connections"], correct:1, explanation:"Behavioral analytics detect anomalies that indicate compromise despite valid credentials, feeding adaptive decisions." },
  { id:60235, domain:1, level:2, question:"Which is the best description of how Zero Trust scales trust decisions?", options:["A human reviewer approves every single access request manually","Trust decisions are pre-baked into static rules that never change","Automation and policy engines enable consistent decisions at large scale","Decisions are delegated entirely to each endpoint's local firewall"], correct:2, explanation:"Automation and centralized policy engines make consistent, scalable decisions; manual review or static rules do not scale." },
  { id:60236, domain:1, level:3, question:"What is the correct relationship between Zero Trust and multi-factor authentication?", options:["MFA fully implements Zero Trust once enabled for all user accounts","MFA is unnecessary in Zero Trust because devices are already trusted","MFA contradicts Zero Trust by adding friction to the login process","MFA strengthens identity verification but is one part of a broader model"], correct:3, explanation:"MFA bolsters identity verification but is just one element; Zero Trust also requires device, context, and continuous evaluation." },
  { id:60237, domain:1, level:1, question:"Which best describes the 'optimal' stage of a Zero Trust maturity model?", options:["Fully automated, dynamic policy with rich cross-pillar visibility and response","A single perimeter firewall with manually maintained, rarely changed static access rules","Implicit trust granted to all internal subnets for efficiency","Authentication performed once per year during compliance audits"], correct:0, explanation:"The optimal stage features automated, dynamic, context-aware policy and strong visibility; the others are immature or contradictory." },
  { id:60238, domain:1, level:2, question:"How does Zero Trust treat a privileged admin session compared to a regular user session?", options:["With relaxed verification to avoid slowing down critical admin work","With even stricter verification given the higher risk of the privileges","Identically, because privilege level does not affect access risk","With no verification, since admins are inherently trusted by the system"], correct:1, explanation:"Higher privilege means higher risk, so Zero Trust applies stricter, not looser, verification to admin sessions." },
  { id:60239, domain:1, level:2, question:"Which statement about Zero Trust and complete elimination of breaches is accurate?", options:["Zero Trust guarantees that no breach can ever occur once deployed","Zero Trust prevents only external breaches, never internal misuse","Zero Trust reduces and contains breaches but cannot guarantee prevention","Zero Trust eliminates the need to plan for incident response at all"], correct:2, explanation:"Zero Trust reduces likelihood and impact but cannot guarantee zero breaches; incident response remains necessary." },
  { id:60240, domain:1, level:3, question:"Why does Zero Trust emphasize the smallest practical implicit trust zone?", options:["Larger zones are easier to manage and therefore always preferred","Smaller zones remove the need for any logging within them","Larger zones improve security by consolidating all controls in one place","Smaller zones limit how far an attacker can act without re-verification"], correct:3, explanation:"Shrinking implicit trust zones limits the area an attacker can traverse without facing fresh verification." },
  { id:60241, domain:1, level:1, question:"Which is an accurate description of the difference between ZTA and ZTNA?", options:["ZTA is the broad architecture; ZTNA is a technology for secure resource access","ZTA and ZTNA are identical terms with no meaningful distinction","ZTNA is the overarching strategy while ZTA is a single product","ZTA applies only to networks while ZTNA applies only to identities"], correct:0, explanation:"Zero Trust Architecture is the overall design; Zero Trust Network Access is a specific technology/category for secure access to resources." },
  { id:60242, domain:1, level:2, question:"How does Zero Trust handle access when contextual risk signals are unavailable?", options:["It defaults to granting full access to avoid disrupting the user","It tends toward denying or limiting access in the absence of assurance","It ignores the missing signals and relies solely on the password","It permanently trusts the request once the network connects"], correct:1, explanation:"Lacking signals to establish trust, Zero Trust leans to deny or limit rather than grant by default." },
  { id:60243, domain:1, level:2, question:"Which is the best example of applying Zero Trust to data?", options:["Trusting all internal applications to read any database freely","Protecting only data that leaves the perimeter toward the internet","Encrypting and access-gating records based on their classification level","Granting every authenticated user read access to all stored data"], correct:2, explanation:"Classifying, encrypting, and gating data by sensitivity reflects the Data pillar; broad internal access does not." },
  { id:60244, domain:1, level:3, question:"What is the role of the 'visibility and analytics' capability in detecting threats?", options:["It routes packets between segments to optimize network performance","It issues and revokes the certificates used by managed devices","It stores encryption keys for protecting data while at rest","It aggregates telemetry to spot anomalies and inform access decisions"], correct:3, explanation:"Visibility and analytics collect and analyze telemetry to detect anomalies and feed decisions; the others are unrelated functions." },
  { id:60245, domain:1, level:1, question:"Which best captures why Zero Trust is considered a strategy rather than a destination?", options:["It is an ongoing program that adapts as threats and the environment change","It is a fixed endpoint reached once a specific product is installed","It is a one-time configuration that never requires future adjustment","It is a certification awarded permanently after a single audit"], correct:0, explanation:"Zero Trust is an evolving strategy that adapts continuously, not a fixed destination or one-time achievement." },
  { id:60246, domain:1, level:2, question:"How does Zero Trust treat the assumption that authenticated equals authorized?", options:["It merges them so that any authenticated subject is fully authorized","It separates them: authentication does not automatically grant authorization","It treats authorization as happening before authentication occurs","It skips authorization entirely once authentication has succeeded"], correct:1, explanation:"Zero Trust keeps authentication and authorization distinct; proving identity does not by itself grant access to a resource." },
  { id:60247, domain:1, level:2, question:"Which is an accurate statement about Zero Trust and operational technology (OT) environments?", options:["Zero Trust cannot apply to OT under any circumstances whatsoever","OT systems are inherently Zero Trust and need no additional controls","Zero Trust principles can extend to OT, though legacy constraints add challenges","Zero Trust in OT means removing all segmentation between devices"], correct:2, explanation:"Zero Trust can extend to OT with adaptations; legacy and availability constraints make it challenging but not impossible." },
  { id:60248, domain:1, level:3, question:"What does Zero Trust recommend when a high-risk anomaly is detected during a session?", options:["Continue the session unchanged since access was already granted","Grant additional privileges so the user can resolve the issue","Wait until the next scheduled login to reassess the user's trust","Step up verification or terminate the session based on the elevated risk"], correct:3, explanation:"Detected high-risk anomalies should trigger step-up verification or session termination, reflecting adaptive access." },
  { id:60249, domain:1, level:1, question:"Which best describes the goal of mapping transaction flows around a protect surface?", options:["To understand legitimate access patterns so policy can be tightly scoped","To identify which firewalls can be safely removed from the perimeter","To justify granting all users broad access to the protect surface","To replace identity verification with flow-based network rules"], correct:0, explanation:"Mapping flows reveals legitimate access patterns, enabling tightly scoped least-privilege policy." },
  { id:60250, domain:1, level:2, question:"How does Zero Trust regard the security of east-west traffic in a data center?", options:["It trusts east-west flows because they stay within the data center","It requires verification of east-west flows to prevent internal pivoting","It inspects only east-west flows and trusts all north-south traffic","It exempts east-west flows that use private IP addressing ranges"], correct:1, explanation:"Zero Trust verifies east-west traffic to stop internal pivoting; staying inside the data center confers no trust." },
  { id:60251, domain:1, level:2, question:"Which statement best reflects Zero Trust's view of trust and time?", options:["Trust, once granted, persists until the account is formally deleted","Trust grows automatically the longer a session remains active","Trust decays and must be re-established rather than persisting indefinitely","Trust is unrelated to time and depends only on the initial login"], correct:2, explanation:"Zero Trust treats trust as time-bounded and decaying, requiring re-establishment rather than indefinite persistence." },
  { id:60252, domain:1, level:3, question:"Why is Zero Trust well suited to environments with bring-your-own-device (BYOD)?", options:["It trusts personal devices fully once the user authenticates once","It bans all personal devices, removing the BYOD question entirely","It trusts BYOD devices because employees are inherently trustworthy","It evaluates device posture per request rather than trusting ownership"], correct:3, explanation:"Zero Trust assesses device posture for each request, handling untrusted BYOD endpoints without granting ownership-based trust." },
  { id:60253, domain:1, level:1, question:"Which is an accurate statement about Zero Trust and zero-day exploits?", options:["Containment and least privilege can limit the impact of a successful exploit","Zero Trust makes systems immune to all zero-day vulnerabilities","Zero Trust prevents zero-days by trusting only internal software","Zero Trust eliminates the need to patch systems against zero-days"], correct:0, explanation:"Zero Trust limits the blast radius of a successful exploit but does not make systems immune or remove the need to patch." },
  { id:60254, domain:1, level:2, question:"How does Zero Trust treat the concept of standing administrative access?", options:["It maximizes it so admins can respond to incidents instantly","It minimizes it in favor of just-in-time elevation when truly needed","It grants permanent admin rights to streamline daily operations","It ignores admin access because admins are trusted by definition"], correct:1, explanation:"Zero Trust minimizes standing admin access, preferring just-in-time elevation to reduce exposure." },
  { id:60255, domain:1, level:2, question:"Which is the best description of Zero Trust's relationship to identity providers (IdPs)?", options:["IdPs are unnecessary because network location establishes identity","IdPs fully replace the need for any authorization policy at all","IdPs supply verified identity that Zero Trust policy decisions rely upon","IdPs are used only for external partners and never internal staff"], correct:2, explanation:"Identity providers furnish the verified identity central to Zero Trust decisions; they support, not replace, authorization policy." },
  { id:60256, domain:1, level:3, question:"What does Zero Trust assume about the trustworthiness of any single signal?", options:["A single strong signal like a password fully establishes trust","The network location signal alone is sufficient to grant access","A valid device certificate alone authorizes all resource access","No single signal is sufficient; decisions combine multiple signals"], correct:3, explanation:"Zero Trust combines multiple signals because no single factor reliably establishes trust on its own." },
  { id:60257, domain:1, level:1, question:"Which is a correct statement about Zero Trust and the elimination of all network boundaries?", options:["Zero Trust does not remove boundaries; it adds finer, identity-aware ones","Zero Trust removes every network boundary and relies on encryption only","Zero Trust keeps only the single outer perimeter and nothing else","Zero Trust eliminates segmentation in favor of one flat trusted network"], correct:0, explanation:"Zero Trust adds finer, identity-aware boundaries (microperimeters); it does not eliminate boundaries or flatten the network." },
  { id:60258, domain:1, level:2, question:"How should an organization treat access to a resource from an unmanaged location and device?", options:["Grant normal access because the user identity is what matters most","Apply the strictest verification and likely limit access given low assurance","Grant access automatically if the resource is internal to the company","Deny logging of the request to reduce noise from untrusted sources"], correct:1, explanation:"Low assurance from unmanaged location and device warrants the strictest verification and likely limited access." },
  { id:60259, domain:1, level:2, question:"Which best describes how Zero Trust handles trust for guest or partner users?", options:["They are trusted broadly once their partner organization vouches for them","They are exempt from device checks because they are external parties","They receive narrowly scoped access verified per request, like all subjects","They inherit the access level of the internal sponsor who invited them"], correct:2, explanation:"Guests and partners get narrowly scoped, per-request verified access; they are not broadly trusted or exempt from checks." },
  { id:60260, domain:1, level:3, question:"Why is 'least privilege' considered foundational rather than optional in Zero Trust?", options:["It speeds up access by removing the need for authorization checks","It allows the perimeter firewall to be safely decommissioned","It eliminates the need to authenticate subjects before access","It directly limits the damage any compromised subject can cause"], correct:3, explanation:"Least privilege constrains the damage from any compromise, a core Zero Trust goal, not an optional convenience." },
  { id:60261, domain:1, level:1, question:"Which statement about Zero Trust and continuous diagnostics is accurate?", options:["Ongoing diagnostics of assets feed the trust decisions made by policy","Diagnostics are run once at deployment and never need repeating","Diagnostics matter only for perimeter devices facing the internet","Diagnostics replace the requirement to authenticate users at all"], correct:0, explanation:"Continuous diagnostics of asset health inform ongoing trust decisions; one-time or perimeter-only checks are insufficient." },
  { id:60262, domain:1, level:2, question:"How does Zero Trust view the relationship between users, devices, and applications?", options:["Only users require verification; devices and apps are always trusted","All three are subjects or resources whose trust must be verified","Only devices matter; user and application identity are irrelevant","Applications are trusted automatically once deployed internally"], correct:1, explanation:"Zero Trust verifies users, devices, and applications as subjects/resources rather than trusting any of them implicitly." },
  { id:60263, domain:1, level:2, question:"Which is the best description of how Zero Trust supports rapid threat response?", options:["Manual ticket approval ensures every revocation is carefully reviewed","Access is fixed at login, so responses wait until the next session","Automated policy can instantly revoke or restrict access when risk rises","Responses are limited to blocking traffic only at the outer perimeter"], correct:2, explanation:"Automation lets Zero Trust revoke or restrict access immediately as risk changes, enabling rapid response." },
  { id:60264, domain:1, level:3, question:"What is a correct understanding of Zero Trust and the principle of explicit deny-by-default?", options:["Everything is permitted unless a policy explicitly blocks it","Internal traffic is permitted while external traffic is blocked","Traffic on well-known ports is always permitted by default","Nothing is permitted unless a policy explicitly allows it"], correct:3, explanation:"Deny-by-default means access requires an explicit allow; the alternatives reintroduce implicit permission." },
  { id:60265, domain:1, level:1, question:"Which best describes how Zero Trust treats a workload migrating between clouds?", options:["Its identity and policy follow it, so access is verified consistently","It loses all access until manually re-trusted by a network admin","It is trusted automatically in the new cloud because it was trusted before","It is exempt from verification while migration is in progress"], correct:0, explanation:"Identity-centric policy follows the workload across clouds, keeping verification consistent rather than location-dependent." },
  { id:60266, domain:1, level:2, question:"Why does Zero Trust treat 'authenticated once, trusted forever' as an anti-pattern?", options:["Authentication is too weak to ever justify granting any access","Conditions change after login, so persistent trust creates exploitable gaps","Persistent trust is required for usability, so it is a best practice","Re-authentication is impossible after the first successful login"], correct:1, explanation:"Persistent trust ignores changing conditions and creates windows for abuse, which is why Zero Trust re-evaluates continuously." },
  { id:60267, domain:1, level:2, question:"Which statement correctly relates Zero Trust to network access control (NAC)?", options:["NAC fully implements Zero Trust by controlling LAN port access","NAC contradicts Zero Trust because it checks devices at the edge","NAC can contribute device posture signals that Zero Trust policy uses","NAC is irrelevant to Zero Trust and should be removed entirely"], correct:2, explanation:"NAC can supply device posture and admission signals feeding Zero Trust decisions; it is a contributor, not the whole model." },
  { id:60268, domain:1, level:3, question:"How does Zero Trust regard the security value of obscurity (hidden assets)?", options:["Obscurity alone is sufficient to protect assets in a Zero Trust model","Hidden assets are exempt from verification because attackers can't find them","Obscurity replaces the need for segmentation around a protect surface","Obscurity is not a substitute for explicit verification and least privilege"], correct:3, explanation:"Zero Trust relies on verification and least privilege, not security through obscurity, which does not establish trust." },
  { id:60269, domain:1, level:1, question:"Which is the best description of how Zero Trust treats trust between business units?", options:["Cross-unit access is explicitly authorized rather than implicitly granted","Units within the same company implicitly trust one another by default","Trust between units is based on the shared corporate IP address space","One unit's authentication automatically authorizes access in another"], correct:0, explanation:"Zero Trust requires explicit authorization for cross-unit access rather than assuming intra-company trust." },
  { id:60270, domain:1, level:2, question:"What does Zero Trust recommend regarding the scope of an access token or session?", options:["Scope it broadly so the user avoids repeated authorization prompts","Scope it narrowly to the specific resources and actions needed","Grant it indefinite lifetime to reduce authentication overhead","Tie it to the network zone rather than to the subject's identity"], correct:1, explanation:"Tokens and sessions should be narrowly scoped and limited, aligning with least privilege and per-request authorization." },
  { id:60271, domain:1, level:2, question:"Which is an accurate statement about Zero Trust and supply-chain or vendor access?", options:["Vendors should receive standing broad access for operational efficiency","Vendor connections are trusted once routed through the corporate VPN","Vendor access should be least privilege, time-bound, and continuously verified","Vendor access needs no monitoring because contracts govern behavior"], correct:2, explanation:"Vendor access follows least privilege, time-bounding, and continuous verification rather than standing broad or unmonitored trust." },
  { id:60272, domain:1, level:3, question:"How does Zero Trust treat the assertion that strong passwords make verification unnecessary?", options:["It accepts this because a strong password fully proves the user's identity","It accepts this only for internal users on the corporate network","It treats passwords as sufficient when combined with a static IP allow rule","It rejects this; passwords are one weak signal among many that are needed"], correct:3, explanation:"Passwords are a single, weak signal; Zero Trust requires multiple signals and continuous verification regardless of password strength." },
  { id:60273, domain:1, level:1, question:"Which best describes how Zero Trust handles access for a dormant or unused account?", options:["Such accounts should be disabled or tightly restricted to reduce risk","Dormant accounts retain full access in case they are needed later","Dormant accounts are trusted more because they have low activity","Dormant accounts are exempt from review since they are not in use"], correct:0, explanation:"Unused accounts expand the attack surface, so Zero Trust restricts or disables them rather than leaving standing access." },
  { id:60274, domain:1, level:2, question:"Why does Zero Trust place controls close to resources rather than only at the network edge?", options:["Resource-side controls are easier to bypass than edge controls","Edge-only controls leave internal paths to resources unguarded","Edge controls already inspect all east-west internal traffic","Placing controls near resources removes the need for identity checks"], correct:1, explanation:"Edge-only controls cannot guard internal paths; placing controls near resources protects them regardless of where traffic originates." },
  { id:60275, domain:1, level:2, question:"Which statement reflects an accurate understanding of Zero Trust and risk-based authentication?", options:["Authentication is identical for every request regardless of context","Authentication is weakest for the most sensitive resources to aid access","Authentication strength scales up as the assessed risk of a request rises","Authentication risk is assessed only for first-time users of a system"], correct:2, explanation:"Risk-based authentication increases verification strength as risk rises, applying stronger checks to higher-risk requests." },
  { id:60276, domain:1, level:3, question:"How does Zero Trust treat the boundary of a containerized microservice environment?", options:["Services inside the same cluster implicitly trust one another fully","Only ingress to the cluster is verified; intra-cluster calls are trusted","Container networking is exempt from Zero Trust due to its complexity","Each service authenticates and authorizes calls regardless of cluster locality"], correct:3, explanation:"Zero Trust verifies service-to-service calls even within a cluster; shared locality does not grant implicit trust." },
  { id:60277, domain:1, level:1, question:"Which best describes the purpose of policy as code in mature Zero Trust programs?", options:["It makes access policies versioned, testable, and consistently enforced","It hard-codes broad trust into the network to reduce overhead","It removes the need for any runtime policy decision point","It applies only to the perimeter firewall configuration files"], correct:0, explanation:"Policy as code makes Zero Trust policies versioned, testable, and consistently applied across the environment." },
  { id:60278, domain:1, level:2, question:"What is an accurate statement about Zero Trust and reducing implicit trust over time?", options:["Maturity means adding implicit trust to speed up internal access","Maturity involves progressively removing implicit trust across all pillars","Implicit trust is acceptable as long as it stays within the data center","Implicit trust should be expanded once microsegmentation is deployed"], correct:1, explanation:"Zero Trust maturity steadily removes implicit trust across pillars rather than adding or preserving it." },
  { id:60279, domain:1, level:2, question:"Which best illustrates Zero Trust applied to API access?", options:["API calls from internal services are trusted without authentication","Only externally exposed APIs require authorization, not internal ones","Each API call is authenticated, authorized, and scoped to least privilege","API gateways grant broad access once a single key is presented"], correct:2, explanation:"Zero Trust authenticates and authorizes each API call with least privilege, including internal calls." },
  { id:60280, domain:1, level:3, question:"How does Zero Trust regard the practice of granting access by job title alone?", options:["Title fully determines access with no further verification needed","Title is irrelevant and access is granted purely by network zone","Title grants permanent access that is never re-evaluated thereafter","Title can inform policy but access should still be verified per request"], correct:3, explanation:"Role/title can inform policy, but Zero Trust still verifies each request rather than granting durable title-based access." },
  { id:60281, domain:1, level:1, question:"Which is the best description of how Zero Trust treats the 'crown jewels' of an organization?", options:["They are identified as protect surfaces and given the tightest controls","They are placed in the most trusted zone and accessed without checks","They are protected only by the outer perimeter firewall and nothing else","They are shared broadly internally to support business agility"], correct:0, explanation:"Critical assets become protect surfaces with the tightest, most granular controls under Zero Trust." },
  { id:60282, domain:1, level:3, question:"What does Zero Trust recommend when an employee changes roles within the company?", options:["Keep all prior access and add the new role's permissions on top","Re-evaluate and adjust their access to match the new role's needs","Grant broad access to ease the transition between roles","Leave access unchanged until the next annual recertification"], correct:1, explanation:"Role changes should trigger re-evaluation and adjustment of access to avoid privilege accumulation, supporting least privilege." },
  { id:60283, domain:1, level:1, question:"Which is an accurate statement about Zero Trust and encrypted traffic inspection?", options:["Encryption means traffic should never be inspected under any circumstances","Inspection is needed only on unencrypted traffic at the perimeter","Visibility into traffic, including decryption where appropriate, aids verification","Encrypted internal traffic is automatically trusted without inspection"], correct:2, explanation:"Zero Trust values visibility, inspecting traffic (decrypting where appropriate) rather than blindly trusting encrypted flows." },
  { id:60284, domain:1, level:3, question:"How does Zero Trust treat the assumption that a managed device is automatically safe?", options:["It trusts managed devices fully because IT controls their configuration","It exempts managed devices from posture checks to reduce friction","It trusts managed devices for the lifetime of their enrollment","It still checks current posture, since a managed device can be compromised"], correct:3, explanation:"Even managed devices can be compromised, so Zero Trust verifies current posture rather than assuming safety from management status." },
  { id:60285, domain:1, level:1, question:"Which best describes how Zero Trust supports compliance audit readiness?", options:["Granular logging and policy provide clear evidence of access decisions","It removes the need for audit logs by trusting all internal activity","It produces evidence only for external internet-facing connections","It replaces auditors with automated approval of all access requests"], correct:0, explanation:"Detailed logging and explicit policy generate strong audit evidence of who accessed what and why under Zero Trust." },
  { id:60286, domain:1, level:3, question:"What is a correct understanding of Zero Trust and decentralized or remote-first organizations?", options:["It cannot work without a central office that anchors the trusted network","It fits well because verification follows identity rather than office location","It requires every employee to connect through one headquarters gateway","It applies only to staff physically present in a corporate facility"], correct:1, explanation:"Zero Trust suits remote-first models because trust follows identity and context, not a physical office." },
  { id:60287, domain:1, level:1, question:"Which statement reflects how Zero Trust treats the principle of redundancy of controls?", options:["A single perfect control removes the need for any other safeguards","Redundant controls contradict Zero Trust by adding complexity","Layered, overlapping controls align with assume-breach and defense-in-depth","Only perimeter controls should be redundant; internal ones need not be"], correct:2, explanation:"Layered, redundant controls support assume-breach thinking and complement Zero Trust, rather than contradicting it." },
  { id:60288, domain:1, level:3, question:"How does Zero Trust treat the question 'where is the user connecting from'?", options:["Location is the primary basis for granting or denying all access","Location is ignored entirely and plays no role in any decision","Location determines trust as long as it is within the corporate range","Location is one risk signal among many, not a basis for implicit trust"], correct:3, explanation:"Zero Trust may use location as a risk signal but never as a basis for implicit trust." },
  { id:60289, domain:1, level:1, question:"Which best describes how Zero Trust treats a compromised credential used from a normal location?", options:["Other signals like device, behavior, and context can still flag and block it","It is allowed because the location appears normal and expected","It is allowed because the credential itself is technically valid","It cannot be detected because location-based trust grants access"], correct:0, explanation:"Zero Trust's multi-signal approach can catch credential misuse via device, behavior, or context even from a normal location." },
  { id:60290, domain:1, level:3, question:"What does Zero Trust recommend about the lifetime of granted sessions?", options:["Make sessions long-lived to minimize repeated authentication prompts","Keep sessions short-lived and subject to re-verification as risk changes","Grant sessions that persist until the user manually logs out","Tie session lifetime to the device's uptime rather than to risk"], correct:1, explanation:"Short-lived, re-verifiable sessions limit the window of misuse, aligning with continuous verification." },
  { id:60291, domain:1, level:1, question:"Which is an accurate statement about Zero Trust and the goal of 'reducing implicit trust to zero'?", options:["It means literally denying all access to every subject permanently","It is achieved instantly the moment a Zero Trust tool is purchased","It is an ideal direction; every access is verified rather than assumed","It applies only to external users, leaving internal trust intact"], correct:2, explanation:"Driving implicit trust toward zero means verifying every access; it does not mean blocking everyone or an instant product fix." },
  { id:60292, domain:1, level:1, question:"How does Zero Trust treat the relationship between segmentation and identity controls?", options:["Segmentation makes identity controls unnecessary in a Zero Trust model","Identity controls replace any need for network segmentation entirely","Segmentation and identity controls conflict and should not be combined","They work together; segmentation limits paths while identity gates access"], correct:3, explanation:"Segmentation and identity controls are complementary in Zero Trust, together limiting paths and gating access." },
  { id:60293, domain:1, level:1, question:"Which best describes the Zero Trust treatment of 'trusted' versus 'untrusted' networks?", options:["The distinction is removed; all networks are treated as untrusted","The internal network remains trusted while the internet is untrusted","Only the DMZ is untrusted while all other networks are trusted","Networks become trusted once they pass an annual vulnerability scan"], correct:0, explanation:"Zero Trust removes the trusted/untrusted network split, treating all networks as untrusted and verifying accordingly." },
  { id:60294, domain:1, level:1, question:"What is the most accurate statement about Zero Trust and incident response?", options:["Zero Trust removes the need for an incident response plan altogether","Rich visibility and segmentation improve detection and containment of incidents","Incident response is needed only for breaches that cross the perimeter","Zero Trust guarantees incidents are resolved without human involvement"], correct:1, explanation:"Zero Trust's visibility and segmentation aid detection and containment, but incident response planning remains essential." },
  { id:60295, domain:1, level:1, question:"Which best describes how Zero Trust treats a request that lacks sufficient context to decide?", options:["It approves the request to avoid blocking legitimate business activity","It defers the decision indefinitely and leaves the resource open","It errs toward caution, denying or limiting access until assurance improves","It grants access based on the source network as a fallback"], correct:2, explanation:"Without sufficient context to establish trust, Zero Trust denies or limits access rather than defaulting to allow." },
  { id:60296, domain:1, level:1, question:"How does Zero Trust regard the claim that it is only relevant to large enterprises?", options:["It is accurate because only large firms have the necessary resources","It is accurate because small organizations have no protect surface","It is accurate because Zero Trust requires a dedicated data center","It is a misconception; the principles scale to organizations of any size"], correct:3, explanation:"Zero Trust principles apply to any size organization; the claim it is only for large enterprises is a misconception." },
  { id:60297, domain:1, level:1, question:"Which statement best reflects Zero Trust's treatment of physical and logical access together?", options:["Both should be governed by verification and least privilege principles","Only logical access matters; physical access is outside Zero Trust","Only physical access matters once the network is segmented","Physical access is implicitly trusted within the corporate building"], correct:0, explanation:"Zero Trust principles extend to both physical and logical access, applying verification and least privilege across both." },
  { id:60298, domain:1, level:1, question:"What does Zero Trust recommend regarding default credentials on devices?", options:["They are acceptable on internal devices behind the corporate firewall","They should be changed and devices verified, as defaults are easily abused","They can remain since device posture checks make them harmless","They are irrelevant because identity controls override device access"], correct:1, explanation:"Default credentials are a known weakness; Zero Trust requires changing them and verifying device posture rather than tolerating them." },
  { id:60299, domain:1, level:1, question:"Which best describes how Zero Trust handles trust propagation across federated systems?", options:["Trust in one federated system automatically extends to all the others","Federation removes the need for per-resource authorization decisions","Trust is established explicitly per system rather than blanket-federated","Federated partners are exempt from continuous verification entirely"], correct:2, explanation:"Zero Trust establishes trust explicitly per system and per request, even across federation, rather than propagating blanket trust." },
  { id:60300, domain:1, level:1, question:"How does Zero Trust treat the assumption that internal developers are inherently trustworthy?", options:["It grants developers broad access because they build the systems","It exempts developers from monitoring to support fast iteration","It trusts developer machines fully since they are corporate assets","It still applies least privilege and verification to developer access"], correct:3, explanation:"Developers receive least-privilege, verified access like everyone else; their role does not grant implicit broad trust." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CCZT_C1 = QUESTIONS_CCZT_C1;
